def solution(acquisition_logs, p95_threshold_ms):
    waits = defaultdict(list)
    for row in acquisition_logs:
        waits[row['lock_key']].append(row['wait_ms'])

    hot = []
    for key, arr in waits.items():
        arr = sorted(arr)
        idx = max(0, min(len(arr) - 1, int((0.95 * len(arr)) - 1)))
